def edit_distance(a: str, b: str) -> int:
    """Return the Levenshtein distance between a and b."""
    m, n = len(a), len(b)
    # dp[i][j] = distance between a[:i] and b[:j]
    dp = [[0] * (n + 1) for _ in range(m + 1)]

    # Base cases: deletions, insertions, and empty strings
    for i in range(m + 1):
        dp[i][0] = i
    for j in range(n + 1):
        dp[0][j] = j

    # Fill the DP table
    for i in range(1, m + 1):
        for j in range(1, n + 1):
            cost = 0 if a[i - 1] == b[j - 1] else 1
            dp[i][j] = min(
                dp[i - 1][j] + 1,      # deletion
                dp[i][j - 1] + 1,      # insertion
                dp[i - 1][j - 1] + cost  # substitution
            )

    return dp[m][n]

def lis_length(nums):
    """Return length of longest strictly increasing subsequence."""
    if not nums:
        return 0
    tails = []  # smallest tails of increasing subsequences of each length
    for x in nums:
        # binary search for first tail >= x
        lo, hi = 0, len(tails)
        while lo < hi:
            mid = (lo + hi) // 2
            if tails[mid] < x:
                lo = mid + 1
            else:
                hi = mid
        # append x to maintain tails
        if lo == len(tails):
            tails.append(x)
        else:
            tails[lo] = x
    return len(tails)
